import{_ as r,o as t,c as n,j as e,a as s,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"苦行者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/1.无支线/苦行者.md","filePath":"4.资源分区/7.物品与装备/3.防具/1.无支线/苦行者.md"}'),o={name:"4.资源分区/7.物品与装备/3.防具/1.无支线/苦行者.md"};function l(_,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"苦行者",tabindex:"-1"},[s("苦行者 "),e("a",{class:"header-anchor",href:"#苦行者","aria-label":'Permalink to "苦行者"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌030")])])],-1),d('<h1 id="苦行者-1" tabindex="-1">苦行者 <a class="header-anchor" href="#苦行者-1" aria-label="Permalink to &quot;苦行者&quot;">​</a></h1><p>苦行者<br> 1000<br> 分类：重甲<br> 自然本质<br> 盔甲基本属性：盔甲防御6/6，盔甲减值8<br> 世界上总有一群人，他们视自己的身体为罪孽的载体，是臭皮囊，必须劳其筋骨、饿其体肤、空乏其身，用这些极端的方式来磨练自己的意志,获得精神的自由和灵魂的解脱。<br> 这是一件由无数碎片,拼凑而成的一套衣物，穿戴在身上会时时感觉到皮肤被割裂，在购买这件护甲时,你需要选择是行于【朝圣之道】还是【入魔之道】。<br> 若你选择行于朝圣之道,这件护甲获得的防御将改为神圣防御，但你在穿上这件护甲的时候所有属性将会强制被降低为2点，且你无法主动去伤害其他生命。若你在一场影片中全程穿戴这件盔甲，则在影片结束后获得10点美名，并使意志豁免获得2dp修行加值。<br> 若你选择行于入魔之道，这件护甲获得的防御将被改为亵渎防御，但是当你在穿上这件护甲的时候你的血量上限将会强制被限制为1点，且无法再获得血量上限，若你在一场影片中全程穿戴这件盔甲，则在影片结束后获得10点恶名，并使你的恐吓检定获得1dp修行加值。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(o,[["render",l]]);export{f as __pageData,m as default};
